import sys
import math

def main():
    N, P = sys.stdin.readline().split()
    N = int(N)
    P = float(P)

    if P == 0.0:
        print(0)
        return

    if P == 1.0:
        print(N-1)
        return

    for k in range(1, N):
        probability = (k / N) * (1 - (math.comb(N - k, 2) / math.comb(N, 2)))
        if probability >= P:
            print(k)
            return

    print(N)

if __name__ == "__main__":
    main()

